package com.school.entity;
import jakarta.persistence.*;
@Entity public class Lecturer extends BaseEntity { @Column(nullable=false,unique=true) private String staffNumber; @Column(nullable=false) private String fullName; @Column(nullable=false,unique=true) private String email; private String phone; @ManyToOne private Department department; @OneToOne private User user; protected Lecturer(){} public Lecturer(String s,String n,String e){staffNumber=s;fullName=n;email=e;} public String getStaffNumber(){return staffNumber;} public String getFullName(){return fullName;} public String getEmail(){return email;} public String getPhone(){return phone;} public User getUser(){return user;} public void setUser(User user){this.user=user;} public void setEmail(String email){this.email=email;} public void setPhone(String phone){this.phone=phone;} }
